package rate

import (
	"fmt"

	"github.com/openmeterio/openmeter/openmeter/billing/rating"
	"github.com/openmeterio/openmeter/openmeter/productcatalog"
)

type Stepped struct {
	ProgressiveBillingMeteredPricer
}

var _ Pricer = (*Stepped)(nil)

func (p Stepped) GenerateDetailedLines(l PricerCalculateInput) (rating.DetailedLines, error) {
	usage, err := l.GetUsage()
	if err != nil {
		return nil, err
	}
	steppedPrice, err := l.GetPrice().AsStepped()
	if err != nil {
		return nil, fmt.Errorf("converting price to stepped price: %w", err)
	}
	if usage.Quantity.IsZero() {
		return nil, nil
	}
	return rating.DetailedLines{{
		Name:                   fmt.Sprintf("%s: usage in period", l.GetName()),
		Quantity:               usage.Quantity,
		PerUnitAmount:          steppedPrice.Amount,
		ChildUniqueReferenceID: rating.UsageChildUniqueReferenceID,
		PaymentTerm:            productcatalog.InArrearsPaymentTerm,
	}}, nil
}
